"use client";
import { useState } from "react";
import ScenarioInput from "./components/ScenarioInput";
import TemplateDropdown from "./components/TemplateDropdown";
import { NameNode } from "./components/ScenarioInput";

export default function HomePage() {
  const [scenarioName, setScenarioName] = useState("");
  const [templateId, setTemplateId] = useState("");

  async function saveScenario() {
    const payload = {
      scenario_name: scenarioName,
    };

    try {
      const res = await fetch("http://localhost:8000/save_scenario", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      if (!res.ok) {
        throw new Error(`Failed to save: ${res.status}`);
      }

      const data = await res.json();
      console.log("Response:", data);
      alert(`${data.filename.replace(".json", "")} Scenario Saved`);
    } catch (err) {
      console.error("Error saving scenario:", err);
    }
  }
  

  return (
    <main className="p-4">
      {/* Header row */}
      <div className="flex items-center justify-between mb-6 relative">
        {/* Left-aligned */}
        <h1 className="text-xl font-bold">Scenario Name</h1>

        {/* Centered absolutely */}
        <div className="absolute left-1/2 transform -translate-x-1/2">
          <h1 className="text-xl font-bold">Scenario Components</h1>
        </div>
      </div>
      <div className="flex justify-center mb-6">
        <TemplateDropdown onChange={setTemplateId} />
      </div>

      {/* Input + button */}
      <div className="flex gap-4">
        <ScenarioInput onChange={setScenarioName}/>
      </div>

      <button
        onClick={saveScenario}
        className="mt-4 px-4 py-2 bg-blue-500 text-white rounded hover:bg-blue-600"
      >
        Save Scenario
      </button>
    </main>
  );
}
